import './App.css';
import {BrowserRouter as Router,Route,Routes} from 'react-router-dom'
import Header from './components/header'
import Footer from './components/footer';


function App() {
  return (
    <div className="App">
      <Header/>
        <Router>
          <Routes>
            <Route path='/' element={<Home/>}></Route>
          </Routes>
        </Router>

      <Footer/>
    </div>
  );
}

export default App;
